const listTransferTxns = `-- name: ListTransferTxns :many
SELECT
  t.txn_no::text AS txn_no,
  t.merchant_no,
  t.out_trade_no,
  COALESCE(t.title, '') AS title,
  COALESCE(t.remark, '') AS remark,
  COALESCE(t.biz_type, '') AS biz_type,
  COALESCE(t.transfer_scene, '') AS transfer_scene,
  COALESCE(t.debit_account_no, '') AS debit_account_no,
  COALESCE(t.credit_account_no, '') AS credit_account_no,
  t.credit_expire_at,
  t.amount,
  COALESCE(t.refund_of_txn_no::text, '')::text AS refund_of_txn_no,
  t.refundable_amount,
  COALESCE(t.status, '') AS status,
  COALESCE(t.error_code, '') AS error_code,
  COALESCE(t.error_msg, '') AS error_msg,
  t.created_at
FROM txn t
WHERE ($1::text = '' OR t.merchant_no = $1::text)
  AND (
    NOT $2::bool
    OR EXISTS (
      SELECT 1
      FROM account a
      JOIN customer c
        ON c.customer_no = a.customer_no
       AND c.merchant_no = t.merchant_no
      WHERE c.out_user_id = $3
        AND (
          a.account_no = t.debit_account_no
          OR a.account_no = t.credit_account_no
        )
    )
  )
  AND (NOT $4::bool OR t.transfer_scene = $5)
  AND (NOT $6::bool OR t.status = $7)
  AND (NOT $8::bool OR t.created_at >= $9::timestamptz)
  AND (NOT $10::bool OR t.created_at <= $11::timestamptz)
  AND (
    NOT $12::bool
    OR (
      t.created_at < $13::timestamptz
      OR (t.created_at = $13::timestamptz AND t.txn_no < $14)
    )
  )
ORDER BY t.created_at DESC, t.txn_no DESC
LIMIT $15
`

