const upsertAccountBookBalance = `-- name: UpsertAccountBookBalance :one
INSERT INTO account_book (book_no, account_no, expire_at, balance)
VALUES (
  NULLIF($1, '')::uuid,
  $2,
  $3::date,
  $4
)
ON CONFLICT (account_no, expire_at)
DO UPDATE SET balance = account_book.balance + EXCLUDED.balance
RETURNING book_no, account_no, expire_at, balance
`

type UpsertAccountBookBalanceParams struct {
	BookNo    interface{}
	AccountNo string
	ExpireAt  pgtype.Date
	Delta     int64
}

type UpsertAccountBookBalanceRow struct {
	BookNo    pgtype.UUID
	AccountNo string
	ExpireAt  pgtype.Date
	Balance   int64
}

func (q *Queries) UpsertAccountBookBalance(ctx context.Context, arg UpsertAccountBookBalanceParams) (UpsertAccountBookBalanceRow, error) {
	row := q.db.QueryRow(ctx, upsertAccountBookBalance,
		arg.BookNo,
		arg.AccountNo,
		arg.ExpireAt,
		arg.Delta,
	)
	var i UpsertAccountBookBalanceRow
	err := row.Scan(
		&i.BookNo,
		&i.AccountNo,
		&i.ExpireAt,
		&i.Balance,
	)
	return i, err
}

